'use strict';
(function() {
  const CAT_SRC = 'data:image/png;base64,';

  const img = document.getElementById('swimming-cat');
  if (!img) return;
  img.src = CAT_SRC;

  const W = () => window.innerWidth;
  const H = () => window.innerHeight;

  const CAT_W = 110;
  const CAT_H = 110;

  const state = {
    x: Math.random() * (W() - CAT_W),
    y: Math.random() * (H() - CAT_H),
    vx: (Math.random() - 0.5) * 0.6,
    vy: (Math.random() - 0.5) * 0.4,
    angle: 0,
    rotSpeed: (Math.random() - 0.5) * 0.008,
    tilt: 0,
    tiltDir: 1,
    tiltSpeed: 0.003 + Math.random() * 0.003,
    tiltMax: 12 + Math.random() * 8,
    bobPhase: Math.random() * Math.PI * 2,
    bobAmp: 6 + Math.random() * 6,
    bobSpeed: 0.012 + Math.random() * 0.008,
    breathePhase: Math.random() * Math.PI * 2,
    scaleX: 1,
  };

  let currentPhaseX = Math.random() * Math.PI * 2;
  let currentPhaseY = Math.random() * Math.PI * 2;

  function tick() {
    currentPhaseX += 0.004;
    currentPhaseY += 0.003;
    const currentX = Math.sin(currentPhaseX) * 0.15;
    const currentY = Math.cos(currentPhaseY) * 0.10;

    state.vx += currentX * 0.02;
    state.vy += currentY * 0.02;

    const maxSpeed = 1.0;
    const speed = Math.hypot(state.vx, state.vy);
    if (speed > maxSpeed) {
      state.vx = (state.vx / speed) * maxSpeed;
      state.vy = (state.vy / speed) * maxSpeed;
    }

    const margin = 20;
    if (state.x < margin)         state.vx += 0.04;
    if (state.x > W() - CAT_W - margin) state.vx -= 0.04;
    if (state.y < margin)         state.vy += 0.04;
    if (state.y > H() - CAT_H - margin) state.vy -= 0.04;

    state.x += state.vx;
    state.y += state.vy;

    state.x = Math.max(0, Math.min(W() - CAT_W, state.x));
    state.y = Math.max(0, Math.min(H() - CAT_H, state.y));

    state.angle += state.rotSpeed;

    state.tilt += state.tiltDir * state.tiltSpeed;
    if (Math.abs(state.tilt) >= state.tiltMax * (Math.PI / 180)) {
      state.tiltDir *= -1;
      state.tiltSpeed = 0.003 + Math.random() * 0.003;
    }

    state.bobPhase += state.bobSpeed;
    const bobY = Math.sin(state.bobPhase) * state.bobAmp;

    state.breathePhase += 0.007;
    const breatheScale = 1 + Math.sin(state.breathePhase) * 0.04;

    if (Math.abs(state.vx) > 0.05) {
      state.scaleX += (Math.sign(state.vx) - state.scaleX) * 0.03;
    }

    const tx = state.x;
    const ty = state.y + bobY;
    const rot = state.angle + state.tilt;

    img.style.transform =
      `translate(${tx}px, ${ty}px) rotate(${rot}rad) scale(${state.scaleX * breatheScale}, ${breatheScale})`;

    img.style.left = '0';
    img.style.top  = '0';

    requestAnimationFrame(tick);
  }

  img.style.position = 'fixed';
  img.style.left = '0';
  img.style.top  = '0';
  img.style.transformOrigin = '50% 50%';

  requestAnimationFrame(tick);
})();
